; ============================================================ ; P2P Presence Verification CDDL Schema ; Reference: draft-rodriguez-h2h-presence-attestation-00 ; ============================================================
; -- Common types --
assurance_value = 1 / 2 ; 1=DEVICE, 2=PRESENCE
; P-256 public key as COSE_Key (kty=EC2, crv=P-256) P256_COSE_Key = { 1 => 2, ; kty: EC2 -1 => 1, ; crv: P-256 -2 => bstr .size 32, ; x coordinate -3 => bstr .size 32, ; y coordinate }
; ============================================================ ; COSE_Sign1 wrappers ; Each signed structure is a COSE_Sign1 with ES256 algorithm. ; The payload is a CBOR-encoded map defined below. ; ============================================================
H2H_COSE_Sign1<PayloadType> = #6.18([ protected: bstr .cbor {1 => -7}, ; alg: ES256 unprotected: {}, payload: bstr .cbor PayloadType, signature: bstr, ])
KeyBindingObject = H2H_COSE_Sign1<KBO_payload> ContactObject = H2H_COSE_Sign1<Contact_payload> SessionCredential = H2H_COSE_Sign1<SC_payload> SignedMessage = H2H_COSE_Sign1<SM_payload> PresenceResponse = H2H_COSE_Sign1<PR_payload>
; ============================================================ ; Payload definitions (no additional keys permitted) ; ============================================================
; -- Key Binding Object --
KBO_payload = { 0 => 1, ; structure_type: KEY_BINDING (fixed) 1 => 1, ; version (fixed for v1) 2 => P256_COSE_Key, ; ik_public 3 => bstr, ; tk_public: raw key bytes 4 => int, ; tk_algorithm: COSE alg id 5 => uint, ; timestamp: Unix ms 6 => uint, ; expiry: Unix ms, max +30d 7 => assurance_value, ; assurance }
; -- Contact Object --
Contact_payload = { 0 => 2, ; structure_type: CONTACT_OBJECT (fixed) 1 => 1, ; version (fixed for v1) 2 => P256_COSE_Key, ; ik_public 3 => bstr, ; tk_public: raw key bytes 4 => int, ; tk_algorithm: COSE alg id 5 => tstr .size (0..64), ; display_name: UTF-8, max 64 bytes 6 => uint, ; timestamp: Unix ms 7 => bstr .size 16, ; nonce: 16 random bytes 8 => bstr .size (0..1024), ; addressing: transport-specific 9 => assurance_value, ; assurance }
; -- Session Credential --
SC_payload = { 0 => 3, ; structure_type: SESSION_CREDENTIAL 1 => 1, ; version (fixed for v1) 2 => P256_COSE_Key, ; ssk_public: ephemeral P-256 key 3 => P256_COSE_Key, ; ik_public: issuing Identity Key 4 => bstr .size 32, ; peer_ik_hash: SHA-256 of peer IK 5 => uint, ; timestamp: Unix ms 6 => uint, ; expiry: Unix ms 7 => assurance_value, ; assurance }
; -- Signed Message --
SM_payload = { 0 => 4, ; structure_type: SIGNED_MESSAGE (fixed) 1 => uint, ; message_id: >= 1, strictly increasing 2 => uint, ; timestamp: Unix ms 3 => uint, ; content_type: application-defined 4 => bstr / tstr, ; content }
; -- Presence Challenge (not signed, plain CBOR) --
PresenceChallenge = { 0 => 16, ; structure_type: PRESENCE_CHALLENGE 1 => bstr .size 32, ; challenge_nonce: 32 random bytes 2 => assurance_value, ; required_assurance }
; -- Presence Response --
PR_payload = { 0 => 17, ; structure_type: PRESENCE_RESPONSE 1 => bstr .size 32, ; challenge_nonce: echoed 2 => assurance_value, ; assurance 3 => bstr .size 32, ; channel_binding: SHA-256 4 => uint, ; timestamp: Unix ms }
